const workflowName = 'facebook_automation_main';
const cycleOwner = crypto.randomUUID();
const driveFolderId = $env.DRIVE_FOLDER_ID || 'root';
const lockTimeout = Number($env.LOCK_TIMEOUT || 900);
const retryLimit = Number($env.RETRY_LIMIT || 3);
const staggerBaseSeconds = Number($env.STAGGER_BASE_SECONDS || 45);
return [{ json: { workflow_name: workflowName, cycle_owner: cycleOwner, drive_folder_id: driveFolderId, lock_timeout: lockTimeout, retry_limit: retryLimit, stagger_base_seconds: staggerBaseSeconds, triggered_at: new Date().toISOString() } }];

const response = $input.first().json;
const files = Array.isArray(response.files) ? response.files : [];
const allowed = new Set(['image/jpeg', 'image/png', 'image/webp', 'image/gif']);
return files.filter(file => file && allowed.has(String(file.mimeType || '').toLowerCase())).map(file => ({ json: { drive_file_id: file.id, file_name: file.name, mime_type: file.mimeType, drive_folder_id: Array.isArray(file.parents) ? file.parents[0] : null, source_url: file.webContentLink || `https://drive.google.com/uc?id=${file.id}`, thumbnail_url: file.thumbnailLink || null, width: file.imageMediaMetadata?.width || null, height: file.imageMediaMetadata?.height || null } }));

const pages = $('Postgres (load pages)').all().map(item => item.json);
const mediaFiles = $('Code (filter images)').all().map(item => item.json);
const control = $('Code (selection logic)').first().json;
if (!pages.length) return [];
function shuffle(array) { const copy = [...array]; for (let i = copy.length - 1; i > 0; i -= 1) { const j = Math.floor(Math.random() * (i + 1)); [copy[i], copy[j]] = [copy[j], copy[i]]; } return copy; }
const groupedByFolder = mediaFiles.reduce((acc, file) => { const key = file.drive_folder_id || 'shared'; if (!acc[key]) acc[key] = []; acc[key].push(file); return acc; }, {});
const sharedPool = [...(groupedByFolder.shared || []), ...(groupedByFolder.drive_shared || [])];
const assignedInCycle = new Set();
const assignments = [];
for (let index = 0; index < pages.length; index += 1) { const page = pages[index]; const folderPool = groupedByFolder[page.drive_folder_id] || []; const eligible = shuffle([...folderPool, ...sharedPool]).filter(file => !assignedInCycle.has(file.drive_file_id)); const selected = eligible[0] || null; const delaySeconds = Math.max(0, Number(page.stagger_seconds || control.stagger_base_seconds || 0) * index); assignments.push({ json: { workflow_name: control.workflow_name, cycle_owner: control.cycle_owner, retry_limit: control.retry_limit, delaySeconds, page, image: selected, assignment_status: selected ? 'assigned' : 'skipped_no_media' } }); if (selected) assignedInCycle.add(selected.drive_file_id); }
return assignments;

