const source = $json;
const assignment = $('Split In Batches (pages)').first().json;
let parsed;
try { const content = source.choices?.[0]?.message?.content || source.body?.choices?.[0]?.message?.content || source.caption_json || '{}'; parsed = typeof content === 'string' ? JSON.parse(content) : content; } catch { parsed = null; }
const hashtags = Array.isArray(parsed?.hashtags) ? parsed.hashtags.filter(Boolean).slice(0, 8) : [];
const hook = String(parsed?.hook || '').trim();
const caption = String(parsed?.caption || '').trim();
const cta = String(parsed?.cta || '').trim();
const confidence = Number(parsed?.confidence ?? 0);
const fallbackCaption = assignment.page.language === 'th' ? `ภาพใหม่สำหรับ ${assignment.page.page_name} พร้อมแชร์แล้ว ดูรายละเอียดเพิ่มเติมได้เลย` : `Fresh post for ${assignment.page.page_name}. Check it out and learn more.`;
const safeCaption = [hook, caption || fallbackCaption, cta, hashtags.join(' ')].filter(Boolean).join('\n\n').slice(0, 2200);
return [{ json: { ...assignment, ai_raw: source, ai_valid: Boolean(caption || hook), caption_payload: { hook: hook || null, caption: caption || fallbackCaption, cta: cta || null, hashtags, confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0.25, final_caption_text: safeCaption } } }];
